// pricing.js
export function calculateTotal(price, quantity, discount) {
  if (price < 0 || quantity < 0) {
    throw new Error('Negative values not allowed');
  }
  let subtotal = price * quantity;
  let discountAmt = subtotal * (discount || 0);
  return subtotal - discountAmt;
}

// pricing.test.js
import { describe, it, expect } from 'vitest';
import { calculateTotal } from './pricing';

describe('calculateTotal', () => {
  it('computes total without discount', () => {
    expect(calculateTotal(10, 3)).toBe(30);
  });
  it('applies percentage discount', () => {
    expect(calculateTotal(100, 2, 0.1)).toBe(180);
  });
  it('rejects negative price', () => {
    expect(() => calculateTotal(-5, 1)).toThrow();
  });
});
